+
+function createSignalAccountOverrideCfg(): OpenClawConfig {
+  return {
+    channels: {
+      signal: {
+        actions: { reactions: false },
+        accounts: {
+          work: { account: "+15550001111", actions: { reactions: true } },
+        },
+      },
+    },
+  } as OpenClawConfig;
