+    expect(
+      signalMessageActions.describeMessageTool?.({ cfg: {} as OpenClawConfig })?.actions ?? [],
+    ).toEqual([]);
+
+    expect(
+      signalMessageActions.describeMessageTool?.({
+        cfg: {
+          channels: { signal: { account: "+15550001111", actions: { reactions: false } } },
+        } as OpenClawConfig,
+      })?.actions,
+    ).toEqual(["send"]);
